import{_ as t,a as e,b as d,c as n,d as i,e as s}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as p,o,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"تحديد الموقع عبر IP وإدارة المستخدمين","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/Other/ip-geolocation-and-user-management.md","filePath":"ar-SA/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),c={name:"ar-SA/Other/ip-geolocation-and-user-management.md"};function h(g,a,u,m,b,P){return o(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="تحديد-الموقع-عبر-ip-وإدارة-المستخدمين" tabindex="-1">تحديد الموقع عبر IP وإدارة المستخدمين <a class="header-anchor" href="#تحديد-الموقع-عبر-ip-وإدارة-المستخدمين" aria-label="Permalink to &quot;تحديد الموقع عبر IP وإدارة المستخدمين&quot;">​</a></h1><p>تحوّل IP geolocation عناوين IP في سجلات الرفع وأجهزة الدخول والسجلات المشابهة إلى مواقع تقريبية.</p><p>بعد ضبطها تستطيع لوحة الإدارة عرض مصادر الرفع والوصول بوضوح أكبر. كما تتيح User Management حظر أو إعادة السماح بالرفع لعناوين IP المشبوهة.</p><h2 id="أين-تضبطها؟" tabindex="-1">أين تضبطها؟ <a class="header-anchor" href="#أين-تضبطها؟" aria-label="Permalink to &quot;أين تضبطها؟&quot;">​</a></h2><p>افتح:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+t+`" alt="IP geolocation" loading="lazy"></p><h2 id="الإعدادات-المتاحة" tabindex="-1">الإعدادات المتاحة <a class="header-anchor" href="#الإعدادات-المتاحة" aria-label="Permalink to &quot;الإعدادات المتاحة&quot;">​</a></h2><p>يدعم مسار IP geolocation الجديد عدة مصادر بدل الاعتماد على خدمة خرائط واحدة.</p><table tabindex="0"><thead><tr><th>الإعداد</th><th>الغرض</th></tr></thead><tbody><tr><td>IP geolocation language</td><td>يحدد لغة العرض، مثل English و Simplified Chinese و Japanese و French وغيرها.</td></tr><tr><td>MaxMind Account ID</td><td>حساب MaxMind لاستخدام MaxMind GeoLite Web Service.</td></tr><tr><td>MaxMind License Key</td><td>مفتاح ترخيص MaxMind.</td></tr><tr><td>Tencent Map Key</td><td>مفتاح Tencent Location Service. مفيد للعناوين الصينية و IP داخل الصين القارية.</td></tr><tr><td>ipapi Key</td><td>مفتاح APILayer ipapi. يدعم تحديد الموقع بعدة لغات.</td></tr></tbody></table><p>املأ الخدمات التي تحتاجها فقط. لا يلزم ضبط كل الحقول.</p><p>إذا لم تُدخل أي مفتاح، سيحاول ImgBed استخدام مصادر مجانية مدمجة، لكن الثبات ودعم اللغة والدقة قد تكون أقل من خدمة تضبطها بنفسك.</p><h2 id="الاختيارات-الموصى-بها" tabindex="-1">الاختيارات الموصى بها <a class="header-anchor" href="#الاختيارات-الموصى-بها" aria-label="Permalink to &quot;الاختيارات الموصى بها&quot;">​</a></h2><p>إذا كنت تحتاج العناوين الصينية غالبًا:</p><ol><li>اجعل IP geolocation language على Simplified Chinese.</li><li>اضبط Tencent Map Key.</li><li>أضف MaxMind أو ipapi اختياريًا كمصادر احتياطية.</li></ol><p>إذا كنت تحتاج الإنجليزية أو عناوين متعددة اللغات:</p><ol><li>اختر اللغة المطلوبة.</li><li>اضبط MaxMind Account ID و License Key.</li><li>أضف ipapi Key إذا أردت نتائج متعددة اللغات أفضل.</li></ol><h2 id="إعداد-maxmind" tabindex="-1">إعداد MaxMind <a class="header-anchor" href="#إعداد-maxmind" aria-label="Permalink to &quot;إعداد MaxMind&quot;">​</a></h2><p>يحتاج MaxMind إلى:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>ابحث عن Account ID في لوحة MaxMind وأنشئ License Key من صفحة License Keys.</p><p><img src="`+e+'" alt="إعداد MaxMind key" loading="lazy"></p><p>بعد الإنشاء، الصق Account ID و License Key في ImgBed واحفظ.</p><p>خطة MaxMind المجانية مناسبة للاستخدام اليومي، لكنها محدودة الطلبات. إذا انتهت الحصة، يواصل ImgBed تجربة المصادر الأخرى المتاحة.</p><h2 id="إعداد-ipapi" tabindex="-1">إعداد ipapi <a class="header-anchor" href="#إعداد-ipapi" aria-label="Permalink to &quot;إعداد ipapi&quot;">​</a></h2><p>يستخدم ipapi مفتاح APILayer API Key.</p><p>افتح لوحة ipapi وانسخ API Key المعروض هناك.</p><p><img src="'+d+'" alt="إعداد ipapi" loading="lazy"></p><p>الصقه في حقل <code>ipapi Key</code> داخل ImgBed واحفظ.</p><p>يدعم ipapi تحديد الموقع بعدة لغات، وهو مفيد عند عرض العناوين بلغة محددة. خطته المجانية محدودة الطلبات أيضًا. إذا انتهت الحصة، يواصل ImgBed تجربة المصادر الأخرى.</p><h2 id="إعداد-tencent-map-key" tabindex="-1">إعداد Tencent Map Key <a class="header-anchor" href="#إعداد-tencent-map-key" aria-label="Permalink to &quot;إعداد Tencent Map Key&quot;">​</a></h2><p>Tencent Map Key مفيد للعناوين الصينية، خصوصًا IP داخل الصين القارية.</p><p>عند إنشاء المفتاح في Tencent Location Service فعّل:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>بعد الإنشاء، الصق المفتاح في <code>Tencent Map Key</code> واحفظ.</p><p>إذا كنت تحتاج تحديدًا أساسيًا لعناوين IP الصينية، فهذا يكفي كبداية.</p><h2 id="ما-الذي-تراجعه-في-user-management؟" tabindex="-1">ما الذي تراجعه في User Management؟ <a class="header-anchor" href="#ما-الذي-تراجعه-في-user-management؟" aria-label="Permalink to &quot;ما الذي تراجعه في User Management؟&quot;">​</a></h2><p>تتوفر User Management من أعلى لوحة الإدارة.</p><p><img src="'+n+'" alt="User management" loading="lazy"></p><p>تعرض User Management نشاط الرفع حسب IP:</p><table tabindex="0"><thead><tr><th>الحقل</th><th>الوصف</th></tr></thead><tbody><tr><td>IP source</td><td>عنوان IP المصدر للرافع.</td></tr><tr><td>Address</td><td>الموقع التقريبي المحلل من IP.</td></tr><tr><td>Total upload size</td><td>إجمالي حجم الملفات المرفوعة من هذا IP.</td></tr><tr><td>Upload count</td><td>عدد الرفعات من هذا IP.</td></tr><tr><td>Upload allowed</td><td>مفعّل يعني أن الرفع مسموح. مغلق يعني أن الرفع محظور.</td></tr></tbody></table><p>اضغط السهم على اليسار لعرض الملفات التي رفعها ذلك IP.</p><p>تعرض قائمة الملفات اسم الملف والمعاينة والحجم ونتيجة المراجعة وحالة الملف ووقت الرفع. إذا بدا النشاط مشبوهًا، افتح IP أولًا وراجع الملفات ثم قرر هل تمنع الرفع لاحقًا.</p><p>إذا كان IP مشبوهًا، أوقف <code>Upload allowed</code>. ستُحظر الرفعات المستقبلية من ذلك IP.</p><h2 id="البحث-والترتيب-والفلاتر-المتقدمة" tabindex="-1">البحث والترتيب والفلاتر المتقدمة <a class="header-anchor" href="#البحث-والترتيب-والفلاتر-المتقدمة" aria-label="Permalink to &quot;البحث والترتيب والفلاتر المتقدمة&quot;">​</a></h2><p>في أعلى User Management يمكنك البحث حسب IP source أو address.</p><p>رتّب حسب الوقت أو upload count أو total upload size للعثور على الرافعين الجدد أو الأكثر تكرارًا أو الأعلى استخدامًا.</p><p>لتحقيق أعمق، افتح advanced filters.</p><p><img src="'+i+'" alt="الفلاتر المتقدمة" loading="lazy"></p><p>تدعم advanced filters:</p><table tabindex="0"><thead><tr><th>الفلتر</th><th>الاستخدام</th></tr></thead><tbody><tr><td>Time range</td><td>عرض IP التي رفعت ملفات خلال فترة محددة.</td></tr><tr><td>Access status</td><td>التصفية حسب normal و blocked وحالات مشابهة.</td></tr><tr><td>Allow/block list</td><td>التصفية حسب allowlist أو blocklist أو unset.</td></tr><tr><td>File type</td><td>عرض IP التي رفعت images أو videos أو audio أو documents أو code أو غيرها.</td></tr><tr><td>File size</td><td>التصفية حسب نطاق حجم الملف المرفوع.</td></tr><tr><td>Age rating</td><td>التصفية حسب unset و General و R12+ و R16+ و R18 وما شابه.</td></tr><tr><td>File status</td><td>التصفية حسب حالة الملف الحالية للتحقق من الملفات غير الطبيعية.</td></tr></tbody></table><p>اضغط <code>Apply Filters</code> للتطبيق. استخدم <code>Reset</code> للعودة إلى كل البيانات.</p><h2 id="عرض-الجوال" tabindex="-1">عرض الجوال <a class="header-anchor" href="#عرض-الجوال" aria-label="Permalink to &quot;عرض الجوال&quot;">​</a></h2><p>على الجوال تتحول User Management إلى عرض بطاقات.</p><p><img src="'+s+`" alt="إدارة المستخدمين على الجوال" loading="lazy"></p><p>تعرض كل بطاقة IP والعنوان وإجمالي حجم الرفع وعدد الرفعات ومفتاح upload allowed. يمكنك إدارة المستخدمين دون تمرير أفقي للجدول.</p><h2 id="إذا-بدا-الموقع-غير-صحيح" tabindex="-1">إذا بدا الموقع غير صحيح <a class="header-anchor" href="#إذا-بدا-الموقع-غير-صحيح" aria-label="Permalink to &quot;إذا بدا الموقع غير صحيح&quot;">​</a></h2><p>تحديد الموقع عبر IP تقريبي وليس عنوانًا دقيقًا.</p><p>إذا كان المستخدم خلف proxy أو data center أو cloud server أو شبكة عابرة للحدود، فقد يختلف الموقع المعروض عن الموقع الحقيقي.</p><p>استخدم هذه الميزة لفهم المصدر التقريبي، واكتشاف الرفعات غير الطبيعية، والمساعدة في قرارات الحظر. لا تعتبرها تتبعًا دقيقًا.</p><h2 id="حالات-شائعة" tabindex="-1">حالات شائعة <a class="header-anchor" href="#حالات-شائعة" aria-label="Permalink to &quot;حالات شائعة&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الحالة</th><th>المعنى</th></tr></thead><tbody><tr><td>Address فارغ</td><td>قد لا يكون IP قد حُلل بعد، أو أن المصدر الحالي غير متاح مؤقتًا.</td></tr><tr><td>لغة Address غير صحيحة</td><td>تحقق من IP geolocation language ومن وجود مصدر يدعم تلك اللغة.</td></tr><tr><td>Address يعرض data center</td><td>كثير من البروكسيات والخوادم السحابية والزواحف تظهر كعناوين data center أو ISP.</td></tr><tr><td>Upload count مرتفع</td><td>راجع هذا IP بعناية واحظر الرفع عند الحاجة.</td></tr><tr><td>Total upload size كبير</td><td>رتّب أو فلتر، وافتح IP، وراجع الملفات المحددة.</td></tr><tr><td>تحتاج إلى الإرجاع بعد الحظر</td><td>أعد تفعيل <code>Upload allowed</code>.</td></tr></tbody></table><h2 id="المسار-السريع" tabindex="-1">المسار السريع <a class="header-anchor" href="#المسار-السريع" aria-label="Permalink to &quot;المسار السريع&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>افتح IP Geolocation في Other Settings</span></span>
<span class="line"><span>-&gt; اختر IP geolocation language</span></span>
<span class="line"><span>-&gt; املأ بيانات MaxMind أو Tencent Map أو ipapi حسب الحاجة</span></span>
<span class="line"><span>-&gt; احفظ الإعدادات</span></span>
<span class="line"><span>-&gt; افتح User Management</span></span>
<span class="line"><span>-&gt; راجع IP source و address و total upload size و upload count</span></span>
<span class="line"><span>-&gt; استخدم البحث أو الترتيب أو advanced filters للعثور على IP غير طبيعي</span></span>
<span class="line"><span>-&gt; اسمح بالرفع أو احظره عند الحاجة</span></span></code></pre></div>`,64)])])}const M=p(c,[["render",h]]);export{y as __pageData,M as default};
